def get_message(request):
    content={}
    if request.user.is_authenticated:
        messages=Message.objects.filter(user_2_id=request.user.id,status=0).exclude(Q(type_1='3')|Q(type_1='5')|Q(type_1='6')|Q(type_1='7')).all()
